#!/bin/bashset -eecho "=== 瀹為獙5锛氭惌寤?Web 鏈嶅姟鍣?==="SERVER_IP=$(ip route get 1 2>/dev/null | awk '{print $7; exit}')[ -z "$SERVER_IP" ] && SERVER_IP="192.168.56.10"echo "鏈嶅姟鍣?IP: $SERVER_IP"echo "[1/6] 瀹夎 Apache 鍜?BIND ..."yum install -y httpd bindecho "[2/6] 鍒涘缓铏氭嫙涓绘満鐩綍 ..."mkdir -p /var/www/test-web1 /var/www/test-web2echo "this is web1" > /var/www/test-web1/index.htmlecho "this is web2" > /var/www/test-web2/index.htmlecho "[3/6] 閰嶇疆 DNS 鍖哄煙 ..."cat >> /etc/named.conf << 'EOF'zone "test-web1.com" IN {    type master;    file "web1.com.zone";};zone "test-web2.com" IN {    type master;    file "web2.com.zone";};EOFcat > /var/named/web1.com.zone << EOF\$TTL 1D@       IN SOA  @ rname.invalid. (                    0       ; serial                    1D      ; refresh                    1H      ; retry                    1W      ; expire                    3H )    ; minimum@       IN NS   www.test-web1.com.www     IN A    ${SERVER_IP}EOFcat > /var/named/web2.com.zone << EOF\$TTL 1D@       IN SOA  @ rname.invalid. (                    0       ; serial                    1D      ; refresh                    1H      ; retry                    1W      ; expire                    3H )    ; minimum@       IN NS   www.test-web2.com.www     IN A    ${SERVER_IP}EOFchown named:named /var/named/web1.com.zone /var/named/web2.com.zoneecho "[4/6] 閰嶇疆 Apache 铏氭嫙涓绘満 ..."cat > /etc/httpd/conf.d/vhosts.conf << EOF<VirtualHost *:80>    ServerAdmin admin@test-web1.com    DocumentRoot /var/www/test-web1    ServerName www.test-web1.com    DirectoryIndex index.html    ErrorLog logs/test-web1.error_log    CustomLog logs/test-web1.access_log common</VirtualHost><VirtualHost *:80>    ServerAdmin admin@test-web2.com    DocumentRoot /var/www/test-web2    ServerName www.test-web2.com    DirectoryIndex index.html    ErrorLog logs/test-web2.error_log    CustomLog logs/test-web2.access_log common</VirtualHost>EOFecho "[5/6] 閰嶇疆闃茬伀澧?..."firewall-cmd --permanent --add-service=http 2>/dev/null || truefirewall-cmd --reload 2>/dev/null || trueecho "[6/6] 鍚姩鏈嶅姟 ..."systemctl enable named httpdsystemctl restart namedsystemctl restart httpdecho ""echo "=== 瀹為獙5 瀹夎瀹屾垚 ==="echo "娴嬭瘯: curl -H 'Host: www.test-web1.com' http://${SERVER_IP}/"echo "娴嬭瘯: curl -H 'Host: www.test-web2.com' http://${SERVER_IP}/"